import{_ as e,o as r,c as i,a2 as s}from"./chunks/framework.Cuq8tsM6.js";const m=JSON.parse('{"title":"Spécifications Print","description":"","frontmatter":{"title":"Spécifications Print"},"headers":[],"relativePath":"docs/fr/advertisers/sponsored-mail/design-guide/print-specs.md","filePath":"docs/fr/advertisers/sponsored-mail/design-guide/print-specs.md"}'),n={name:"docs/fr/advertisers/sponsored-mail/design-guide/print-specs.md"};function d(o,t,l,a,g,p){return r(),i("div",null,[...t[0]||(t[0]=[s('<h1 id="specifications-techniques" tabindex="-1">Spécifications Techniques <a class="header-anchor" href="#specifications-techniques" aria-label="Permalink to &quot;Spécifications Techniques&quot;">​</a></h1><p>Les contraintes impératives pour garantir une qualité d&#39;impression et de distribution optimale.</p><hr><h2>📐 Formats Papier (Flyers)</h2><table tabindex="0"><thead><tr><th style="text-align:left;">Format</th><th style="text-align:left;">Format fini (Découpé)</th><th style="text-align:left;">Format fichier (Avec fond perdu)</th><th style="text-align:left;">Zone tranquille</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>A5</strong></td><td style="text-align:left;">148 x 210 mm</td><td style="text-align:left;"><strong>152 x 214 mm</strong></td><td style="text-align:left;">3 mm internes</td></tr><tr><td style="text-align:left;"><strong>A6</strong></td><td style="text-align:left;">105 x 148 mm</td><td style="text-align:left;"><strong>109 x 152 mm</strong></td><td style="text-align:left;">3 mm internes</td></tr><tr><td style="text-align:left;"><strong>Carte</strong></td><td style="text-align:left;">105 x 148 mm</td><td style="text-align:left;"><strong>109 x 152 mm</strong></td><td style="text-align:left;">Voir Gabarit</td></tr></tbody></table><br><div style="display:flex;gap:20px;flex-wrap:wrap;margin-bottom:40px;"><div style="flex:1;background:var(--gi-tint-red-bg);border:1px solid var(--gi-tint-red-text);padding:15px;border-radius:6px;"><strong class="text-red-200">Fond Perdu (Bleed) : 2mm</strong><br> La matière (image/fond) doit déborder de 2mm à l&#39;extérieur pour éviter les liserés blancs. </div><div style="flex:1;background:var(--gi-tint-green-bg);border:1px solid var(--gi-tint-green-text);padding:15px;border-radius:6px;"><strong>Zone Tranquille : 3mm</strong><br> Aucun texte ni logo important ne doit se trouver à moins de 3mm du bord intérieur. </div></div><h2>🎁 Formats Échantillons (Sampling)</h2><p>getinside permet la distribution d&#39;échantillons seuls ou assemblés.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Taille</th><th style="text-align:left;">Poids Max</th><th style="text-align:left;">Développé Max (H + l + L)</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Format S</strong></td><td style="text-align:left;">Jusqu&#39;à <strong>15g</strong></td><td style="text-align:left;">Jusqu&#39;à <strong>15 cm</strong></td></tr><tr><td style="text-align:left;"><strong>Format M</strong></td><td style="text-align:left;">Jusqu&#39;à <strong>100g</strong></td><td style="text-align:left;">Jusqu&#39;à <strong>30 cm</strong></td></tr><tr><td style="text-align:left;"><strong>Format L</strong></td><td style="text-align:left;">Jusqu&#39;à <strong>450g</strong></td><td style="text-align:left;">Jusqu&#39;à <strong>40 cm</strong></td></tr></tbody></table><br><div style="margin-top:20px;border:1px solid var(--vp-c-divider);border-radius:8px;overflow:hidden;"><div style="background:var(--vp-c-bg-soft);padding:15px;border-bottom:1px solid var(--vp-c-divider);font-weight:bold;"> ✨ Service d&#39;Assemblage (Flyer + Échantillon) </div><div style="padding:24px;background:var(--vp-c-bg-elv);"><h3>Option &quot;Duo&quot; (Format S uniquement)</h3><p>Nous pouvons coller votre échantillon (taille S) sur un flyer A5 ou A6 pour maximiser l&#39;impact visuel.</p><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(250px, 1fr));gap:20px;margin-top:20px;"><div><strong>Technique :</strong><br> Utilisation d&#39;un point de <strong>colle fugitive</strong> (repositionnable) qui permet de détacher l&#39;échantillon sans abîmer le flyer. </div><div><strong>Engagement RSE :</strong><br> Cette prestation est réalisée par des <strong>Entreprises Adaptées (EA)</strong>. </div></div></div></div><h2>🌐 Fichiers &amp; Couleurs</h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(300px, 1fr));gap:20px;width:100%;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);"><h3>📁 Type de fichier</h3><ul><li><strong>PDF/X (Vectoriel) :</strong> À privilégier.</li><li><strong>JPG / PNG :</strong> 300 DPI minimum.</li></ul></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);"><h3>🎨 Colorimétrie</h3><ul><li><strong>Mode :</strong> CMJN obligatoire.</li><li><strong>Profil :</strong> Coated FOGRA39.</li><li><strong>Taux d&#39;encrage :</strong> Max 300%.</li></ul></div></div><h2>📋 Gestion des Surplus &amp; Avaries</h2><div style="border:2px solid var(--gi-accent);border-radius:8px;padding:24px;background:var(--gi-tint-blue-bg);margin-bottom:30px;"><h3>Article 38 - Code des Usages de l&#39;Industrie Graphique (UIIC)</h3><p>La réception de tout tirage est soumise à la tolérance d&#39;écart fixée par l&#39;industrie de l&#39;imprimerie.</p><div style="margin-top:15px;padding:15px;background:var(--vp-c-bg-elv);border-radius:6px;"><strong>Écarts acceptés :</strong><ul style="margin:0.5rem 0 0;"><li><strong>Tirages ≤ 2 000 ex :</strong> ±10%</li><li><strong>Tirages 2 000-10 000 ex :</strong> ±5%</li><li><strong>Tirages 10 000-100 000 ex :</strong> ±3%</li><li><strong>Tirages &gt; 100 000 ex :</strong> ±2%</li></ul><p style="margin:1rem 0 0;font-size:0.9em;color:var(--vp-c-text-2);"><em>Example : Pour un tirage de 10 000 unités, une production entre 9 500 et 10 500 unités est conforme.</em></p></div></div><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(280px, 1fr));gap:20px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);"><h3>✅ Surplus Acceptés</h3><p>Les écarts de production sont normaux et légalement acceptés conformément à l&#39;Article 38 UIIC.</p><p><strong>Aucune pénalité ou remise n&#39;est applicable.</strong></p></div><div style="border:1px solid var(--gi-tint-red-text);border-radius:8px;padding:20px;background:var(--gi-tint-red-bg);"><h3>⚠️ Avaries Mineures</h3><p>Une avarie mineure (&lt; 1% du volume) ne doit pas bloquer la distribution.</p><p>L&#39;impact sur votre budget est limité ; continuez la diffusion.</p></div></div>',17)])])}const c=e(n,[["render",d]]);export{m as __pageData,c as default};
